(function () {
  window._b64beacon = "ZmxhZ3tiNHMzXzY0X2IzNGMwbn0=";

  // Flag-checking and user data both live server-side now.
  // Nothing here can be read in DevTools to skip a challenge.

  window.fetchUser = async function (id) {
    try {
      const res = await fetch("/api/user?id=" + encodeURIComponent(id));
      const user = await res.json();
      if (!res.ok) {
        console.log("[API] " + res.status + " — " + (user.error || "error"));
        return;
      }
      console.log("[API /api/user?id=" + id + "]", JSON.stringify(user, null, 2));
      if (user.secret_flag) {
        console.log("%c[!] IDOR FLAG FOUND: " + user.secret_flag, "color:#22c55e;font-family:monospace;font-weight:bold;font-size:14px");
        revealBonus(user.secret_flag);
        autoSolveBonus(user.secret_flag);
      }
    } catch (e) {
      console.error("[API] fetchUser failed", e);
    }
  };

  console.log("%c[CTF] BONUS: Try window.fetchUser(1) then window.fetchUser(2) — spot the IDOR!", "color:#22d3ee;font-family:monospace;font-size:12px");

  const sessionId = Math.random().toString(36).slice(2, 10).toUpperCase();
  const sessionEl = document.getElementById("ptf-session");
  if (sessionEl) sessionEl.textContent = sessionId;

  let solved = JSON.parse(localStorage.getItem("ptf_solved") || "[false,false,false,false]");
  if (solved.length < 4) solved = [solved[0] || false, solved[1] || false, solved[2] || false, false];

  function persist() {
    try {
      localStorage.setItem("ptf_solved", JSON.stringify(solved));
    } catch (e) {}
  }

  function mainSolvedCount() {
    return solved.slice(0, 3).filter(Boolean).length;
  }

  function revealBonus(flagText) {
    const panel = document.getElementById("ptf-idor-hint");
    if (panel) {
      panel.style.display = "block";
      const reveal = document.getElementById("idor-flag-reveal");
      if (reveal) reveal.textContent = flagText;
    }
  }

  // Asks the backend whether `guess` is the right answer for challenge `idx`.
  // The actual answers are never sent to the browser - only true/false comes back.
  async function verifyFlag(idx, guess) {
    try {
      const res = await fetch("/api/check-flag", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ idx: idx, guess: guess })
      });
      if (!res.ok) return false;
      const data = await res.json();
      return !!data.correct;
    } catch (e) {
      console.error("[CTF] Could not reach the flag-checking API", e);
      return false;
    }
  }

  async function autoSolveBonus(flagText) {
    if (solved[3]) return;
    const ok = await verifyFlag(3, flagText);
    if (!ok) return;
    solved[3] = true;
    persist();
    const bonusInput = document.getElementById("ptf-in-3");
    if (bonusInput) bonusInput.value = flagText;
    render();
  }

  // ---- BONUS CHALLENGE VISIBILITY ----
  // Bonus card (index 3) should only be visible after all 3 main challenges are solved
  function updateBonusVisibility() {
    const bonusCard = document.getElementById("ptf-card-3");
    const mainCount = mainSolvedCount();
    if (bonusCard) {
      bonusCard.style.display = mainCount < 3 ? "none" : "block";
    }
  }

  function render() {
    const mainCount = mainSolvedCount();
    const pct = Math.round(mainCount / 3 * 100);

    const bar = document.getElementById("ptf-progress-bar");
    if (bar) bar.style.width = pct + "%";

    const countEl = document.getElementById("ptf-solved-count");
    if (countEl) countEl.textContent = mainCount;

    const pctEl = document.getElementById("ptf-pct");
    if (pctEl) pctEl.textContent = mainCount + "/3";

    solved.forEach(function (isSolved, idx) {
      // Only update lock icons 0-2 (main challenges)
      if (idx < 3) {
        const lock = document.getElementById("ptf-lock-" + idx);
        if (lock && isSolved) {
          lock.classList.add("unlocked");
          lock.innerHTML = '<i class="fas fa-unlock"></i><div style="font-size:.5rem;margin-top:.2rem;color:var(--g)">SOLVED</div>';
        }
      }
      const status = document.getElementById("ptf-status-" + idx);
      if (status && isSolved) {
        status.className = "ptf-badge solved-badge";
        status.innerHTML = '<i class="fas fa-check"></i> SOLVED';
      }
      const card = document.getElementById("ptf-card-" + idx);
      if (card && isSolved) {
        card.style.borderColor = "rgba(34,197,94,.5)";
        card.style.boxShadow = "0 0 16px rgba(34,197,94,.15)";
      }
    });

    // Show winner banner only when all 3 main are solved
    const winner = document.getElementById("ptf-winner");
    if (winner) {
      winner.style.display = mainCount === 3 ? "block" : "none";
    }

    const tease = document.getElementById("ptf-winner-tease");
    if (tease) {
      tease.style.display = mainCount === 3 && !solved[3] ? "block" : "none";
    }

    updateBonusVisibility();

    // The IDOR bonus is the actual gate for the admin console - solving it
    // is enough on its own, matching the hint shown on /admin.
    if (solved[3]) {
      unlockAdminPanel();
    }
  }

  function unlockAdminPanel() {
    const statusLine = document.getElementById("ptf-final-status");
    if (statusLine && statusLine.dataset.fired === "1") return;
    if (statusLine) statusLine.dataset.fired = "1";

    try {
      sessionStorage.setItem("ctf_unlocked", "true");
    } catch (e) {}

    if (statusLine) {
      statusLine.style.display = "block";
      statusLine.innerHTML = 'ACCESS LEVEL: ROOT — <a href="/admin" style="color:var(--g);text-decoration:underline">enter the mainframe &rarr;</a>';
    }
  }

  window.checkFlag = async function (idx) {
    const input = document.getElementById("ptf-in-" + idx);
    const feedback = document.getElementById("ptf-fb-" + idx);
    if (!input || !feedback) return;

    const guess = input.value.trim();
    const buttons = document.querySelectorAll("#ptf-card-" + idx + " .ptf-hack-btn");
    buttons.forEach(function (b) { b.disabled = true; });
    feedback.textContent = "CHECKING...";
    feedback.className = "ptf-feedback";

    const correct = await verifyFlag(idx, guess);

    if (correct) {
      solved[idx] = true;
      persist();
      feedback.textContent = "✓ CORRECT! Flag accepted.";
      feedback.className = "ptf-feedback correct";
      input.disabled = true;
      buttons.forEach(function (b) {
        b.disabled = true;
        b.style.opacity = ".4";
      });
      render();
    } else {
      feedback.textContent = "✗ Wrong flag. Keep digging.";
      feedback.className = "ptf-feedback wrong";
      input.style.borderColor = "rgba(239,68,68,.5)";
      buttons.forEach(function (b) { b.disabled = false; });
      setTimeout(function () {
        input.style.borderColor = "";
      }, 1200);
    }
  };

  window.toggleHint = function (idx) {
    const hint = document.getElementById("ptf-hint-" + idx);
    const btn = hint && hint.previousElementSibling;
    if (!hint) return;
    const isOpen = hint.style.display !== "none";
    hint.style.display = isOpen ? "none" : "block";
    if (btn) btn.textContent = (isOpen ? "▶" : "▼") + " " + (isOpen ? "SHOW" : "HIDE") + " HINT";
  };

  [0, 1, 2, 3].forEach(function (idx) {
    const input = document.getElementById("ptf-in-" + idx);
    if (input) {
      input.addEventListener("keydown", function (e) {
        if (e.key === "Enter") window.checkFlag(idx);
      });
    }
  });

  render();

  console.log("%c[iamunknown77 CTF] 3 challenges + 1 bonus active. Good luck, hacker.", "color:#22c55e;font-size:13px;font-family:monospace;font-weight:bold");
  console.log("%c  Ch1: Decode window._b64beacon  |  Ch2: Read page source  |  Ch3: ROT13 FRPHEVGL", "color:#22d3ee;font-size:11px;font-family:monospace");
  console.log("%c  BONUS (IDOR): window.fetchUser(1) → window.fetchUser(2)  [unlocks /admin]", "color:#c026d3;font-size:11px;font-family:monospace");
})();
